class RecentCounter {
public:
    vector<int> pings;

    int ping(int t)
    {
        pings.push_back(t);
        int count = 0;
        for (int p : pings)
        {
            if (p >= t - 3000) count++;
        }
        return count;
    }
};

int main()
{
    RecentCounter rc;
    cout << rc.ping(1) << " " << rc.ping(100) << " " << rc.ping(3001) << " " << rc.ping(3002) << endl;

