}

#include <iostream>
#include <queue>

using namespace std;

class RecentCounter {
public:
    queue<int> requests;

    int ping(int t)
    {
        requests.push(t);

        while (requests.front() < t - 3000)
        {
            requests.pop();
        }

        return requests.size();
    }
};

int main()
{
    RecentCounter rc;
    cout << rc.ping(1) << " " << rc.ping(100) << " " << rc.ping(3001) << " " << rc.ping(3002) << endl;

    return 0;
}

#include <iostream>
#include <stack>

using namespace std;

class MyQueue {
public:
    stack<int> s;

    void push(int x)
    {
        stack<int> temp;
        while (!s.empty()) { temp.push(s.top()); s.pop(); }
        temp.push(x);
        while (!temp.empty()) { s.push(temp.top()); temp.pop(); }
    }

    int pop() { int front = s.top(); s.pop(); return front; }
    int peek() { return s.top(); }
    bool empty() { return s.empty(); }
};

int main()
{
    MyQueue q;
    q.push(1);
    q.push(2);
    cout << q.peek() << ", ";
    cout << q.pop() << ", ";
    cout << (q.empty() ? "true" : "false") << endl;

    return 0;
}

#include <iostream>
#include <stack>

using namespace std;

class MyQueue {
public:
    stack<int> in, out;

    void transferIfNeeded()
    {
        if (out.empty())
        {
            while (!in.empty()) { out.push(in.top()); in.pop(); }
        }
    }

    void push(int x) { in.push(x); }

    int pop()
    {
        transferIfNeeded();
        int front = out.top();
        out.pop();
        return front;
    }

    int peek()
    {
        transferIfNeeded();
        return out.top();
    }

    bool empty() { return in.empty() && out.empty(); }
};

int main()
{
    MyQueue q;
    q.push(1);
    q.push(2);
    cout << q.peek() << ", ";
    cout << q.pop() << ", ";
    cout << (q.empty() ? "true" : "false") << endl;

    return 0;
}

